652: absl::optional<uint32_t>
653: HostSetImpl::chooseLocality(EdfScheduler<LocalityEntry>* locality_scheduler) {
654:   if (locality_scheduler == nullptr) {
655:     return {};
656:   }
657:   const std::shared_ptr<LocalityEntry> locality = locality_scheduler->pickAndAdd(
658:       [](const LocalityEntry& locality) { return locality.effective_weight_; });
659:   // We don't build a schedule if there are no weighted localities, so we should always succeed.
660:   ASSERT(locality != nullptr);
661:   // If we picked it before, its weight must have been positive.
662:   ASSERT(locality->effective_weight_ > 0);
663:   return locality->index_;
664: }
