707: double HostSetImpl::effectiveLocalityWeight(uint32_t index,
708:                                             const HostsPerLocality& eligible_hosts_per_locality,
709:                                             const HostsPerLocality& excluded_hosts_per_locality,
710:                                             const HostsPerLocality& all_hosts_per_locality,
711:                                             const LocalityWeights& locality_weights,
712:                                             uint32_t overprovisioning_factor) {
713:   const auto& locality_eligible_hosts = eligible_hosts_per_locality.get()[index];
714:   const uint32_t excluded_count = excluded_hosts_per_locality.get().size() > index
715:                                       ? excluded_hosts_per_locality.get()[index].size()
716:                                       : 0;
717:   const auto host_count = all_hosts_per_locality.get()[index].size() - excluded_count;
718:   if (host_count == 0) {
719:     return 0.0;
720:   }
721:   const double locality_availability_ratio = 1.0 * locality_eligible_hosts.size() / host_count;
722:   const uint32_t weight = locality_weights[index];
723:   // Availability ranges from 0-1.0, and is the ratio of eligible hosts to total hosts, modified
724:   // by the overprovisioning factor.
725:   const double effective_locality_availability_ratio =
726:       std::min(1.0, (overprovisioning_factor / 100.0) * locality_availability_ratio);
727:   return weight * effective_locality_availability_ratio;
728: }
