748: void PrioritySetImpl::updateHosts(uint32_t priority, UpdateHostsParams&& update_hosts_params,
749:                                   LocalityWeightsConstSharedPtr locality_weights,
750:                                   const HostVector& hosts_added, const HostVector& hosts_removed,
751:                                   absl::optional<bool> weighted_priority_health,
752:                                   absl::optional<uint32_t> overprovisioning_factor,
753:                                   HostMapConstSharedPtr cross_priority_host_map) {
754:   // Update cross priority host map first. In this way, when the update callbacks of the priority
755:   // set are executed, the latest host map can always be obtained.
756:   if (cross_priority_host_map != nullptr) {
757:     const_cross_priority_host_map_ = std::move(cross_priority_host_map);
758:   }
759: 
760:   // Ensure that we have a HostSet for the given priority.
761:   getOrCreateHostSet(priority, weighted_priority_health, overprovisioning_factor);
762:   static_cast<HostSetImpl*>(host_sets_[priority].get())
763:       ->updateHosts(std::move(update_hosts_params), std::move(locality_weights), hosts_added,
764:                     hosts_removed, weighted_priority_health, overprovisioning_factor);
765: 
766:   if (!batch_update_) {
767:     runUpdateCallbacks(hosts_added, hosts_removed);
768:   }
769: }
