784: void PrioritySetImpl::BatchUpdateScope::updateHosts(
785:     uint32_t priority, PrioritySet::UpdateHostsParams&& update_hosts_params,
786:     LocalityWeightsConstSharedPtr locality_weights, const HostVector& hosts_added,
787:     const HostVector& hosts_removed, absl::optional<bool> weighted_priority_health,
788:     absl::optional<uint32_t> overprovisioning_factor) {
789:   // We assume that each call updates a different priority.
790:   ASSERT(priorities_.find(priority) == priorities_.end());
791:   priorities_.insert(priority);
792: 
793:   for (const auto& host : hosts_added) {
794:     all_hosts_added_.insert(host);
795:   }
796: 
797:   for (const auto& host : hosts_removed) {
798:     all_hosts_removed_.insert(host);
799:   }
800: 
801:   parent_.updateHosts(priority, std::move(update_hosts_params), locality_weights, hosts_added,
802:                       hosts_removed, weighted_priority_health, overprovisioning_factor);
803: }
