1660: absl::Status ClusterImplBase::parseDropOverloadConfig(
1661:     const envoy::config::endpoint::v3::ClusterLoadAssignment& cluster_load_assignment) {
1662:   // Default drop_overload_ to zero.
1663:   drop_overload_ = UnitFloat(0);
1664: 
1665:   if (!cluster_load_assignment.has_policy()) {
1666:     return absl::OkStatus();
1667:   }
1668:   auto policy = cluster_load_assignment.policy();
1669:   if (policy.drop_overloads().size() == 0) {
1670:     return absl::OkStatus();
1671:   }
1672:   if (policy.drop_overloads().size() > kDropOverloadSize) {
1673:     return absl::InvalidArgumentError(
1674:         fmt::format("Cluster drop_overloads config has {} categories. Envoy only support one.",
1675:                     policy.drop_overloads().size()));
1676:   }
1677: 
1678:   const auto drop_percentage = policy.drop_overloads(0).drop_percentage();
1679:   float denominator = 100;
1680:   switch (drop_percentage.denominator()) {
1681:   case envoy::type::v3::FractionalPercent::HUNDRED:
1682:     denominator = 100;
1683:     break;
1684:   case envoy::type::v3::FractionalPercent::TEN_THOUSAND:
1685:     denominator = 10000;
1686:     break;
1687:   case envoy::type::v3::FractionalPercent::MILLION:
1688:     denominator = 1000000;
1689:     break;
1690:   default:
1691:     return absl::InvalidArgumentError(fmt::format(
1692:         "Cluster drop_overloads config denominator setting is invalid : {}. Valid range 0~2.",
1693:         drop_percentage.denominator()));
1694:   }
1695:   drop_overload_ = UnitFloat(float(drop_percentage.numerator()) / (denominator));
1696:   return absl::OkStatus();
1697: }
