1741:     HostVectorConstSharedPtr hosts_copy = std::make_shared<HostVector>(host_set->hosts());
1742: 
1743:     HostsPerLocalityConstSharedPtr hosts_per_locality_copy = host_set->hostsPerLocality().clone();
1744:     prioritySet().updateHosts(priority,
1745:                               HostSetImpl::partitionHosts(hosts_copy, hosts_per_locality_copy),
