2035:   LocalityWeightsMap& locality_weights_map =
2036:       priority_state_.size() > priority ? priority_state_[priority].second : empty_locality_map;
2037:   ASSERT(priority_state_.size() > priority || locality_weights_map.empty());
2038:   LocalityWeightsSharedPtr locality_weights;
2039:   std::vector<HostVector> per_locality;
2040: 
2041:   // If we are configured for locality weighted LB we populate the locality weights. We also
2042:   // populate locality weights if the cluster uses load balancing extensions, since the extension
2043:   // may want to make use of locality weights and we cannot tell by inspecting the config whether
2044:   // this is the case.
2045:   //
2046:   // TODO: have the load balancing extension indicate, programmatically, whether it needs locality
2047:   // weights, as an optimization in cases where it doesn't.
2048:   const bool locality_weighted_lb =
2049:       parent_.info()->lbConfig().has_locality_weighted_lb_config() ||
2050:       parent_.info()->lbType() == LoadBalancerType::LoadBalancingPolicyConfig;
2051:   if (locality_weighted_lb) {
2052:     locality_weights = std::make_shared<LocalityWeights>();
2053:   }
2054: 
2055:   // We use std::map to guarantee a stable ordering for zone aware routing.
2056:   std::map<envoy::config::core::v3::Locality, HostVector, LocalityLess> hosts_per_locality;
2057: 
2058:   for (const HostSharedPtr& host : *hosts) {
2059:     // Take into consideration when a non-EDS cluster has active health checking, i.e. to mark all
2060:     // the hosts unhealthy (host->healthFlagSet(Host::HealthFlag::FAILED_ACTIVE_HC)) and then fire
2061:     // update callbacks to start the health checking process. The endpoint with disabled active
2062:     // health check should not be set FAILED_ACTIVE_HC here.
2063:     if (health_checker_flag.has_value() && !host->disableActiveHealthCheck()) {
2064:       host->healthFlagSet(health_checker_flag.value());
2065:     }
2066:     hosts_per_locality[host->locality()].push_back(host);
2067:   }
2068: 
2069:   // Do we have hosts for the local locality?
