2074:   // As per HostsPerLocality::get(), the per_locality vector must have the local locality hosts
2075:   // first if non_empty_local_locality.
2076:   if (non_empty_local_locality) {
2077:     per_locality.emplace_back(hosts_per_locality[local_locality]);
2078:     if (locality_weighted_lb) {
2079:       locality_weights->emplace_back(locality_weights_map[local_locality]);
2080:     }
